function modifier(
  reading: string,
  triggerTerms: string[],
  weight = 0.75,
  fortuneValence?: FortuneValence,
): SceneModifier {
  return { reading, triggerTerms, weight, ...(fortuneValence ? { fortuneValence } : {}) };
}

function localized(input: {
  label: string;
  aliases: string[];
  searchText: string;
  coreMeanings: string[];
  lightReadings: string[];
  shadowReadings: string[];
  sceneModifiers: Record<string, SceneModifier>;
  contextQuestions: string[];
  metaphorHooks: string[];
  cardTitleSeeds: string[];
  smallPrescriptions: string[];
  safeReading: string;
  avoidExpressions: string[];
  fortune?: SymbolFortune;
}): LocalizedSymbolEntry {
  return input;
}

const embeddingProfile: EmbeddingProfile = {
  chunkTypes: ["searchText", "sceneModifier", "safeReading", "metaphorHook"],
};

type ActiveSymbolInput = {
  id: string;
  category: SymbolEntry["category"];
  subcategory: string;
  facets: string[];
  symbolRole: SymbolEntry["symbolRole"];
  safetyLevel?: SymbolEntry["safetyLevel"];
  accessTier?: SymbolEntry["accessTier"];
  universalMeanings: string[];
  relatedIds: string[];
  sourceBasis: string[];
  disambiguation?: SymbolDisambiguation;
  ko: LocalizedSymbolEntry;
  en: LocalizedSymbolEntry;
};

function activeSymbol(input: ActiveSymbolInput): SymbolEntry {
  return {
    id: input.id,
    status: "active",
    editorialStatus: "approved",
    category: input.category,
    subcategory: input.subcategory,
    facets: input.facets,
    symbolRole: input.symbolRole,
    safetyLevel: input.safetyLevel ?? "safe",
    accessTier: input.accessTier ?? "free",
    embeddingProfile,
    universalMeanings: input.universalMeanings,
    relatedIds: input.relatedIds,
    sourceBasis: input.sourceBasis,
    ...(input.disambiguation ? { disambiguation: input.disambiguation } : {}),
    locales: {
      ko: input.ko,
      en: input.en,
    },
  };
}

type ExpansionLocalizedInput = {
  label: string;
  aliases: string[];
  searchText: string;
  coreMeanings: string[];
  lightReadings: string[];
  shadowReadings: string[];
  sceneModifiers: Record<string, SceneModifier>;
  contextQuestions: string[];
  metaphorHooks: string[];
  cardTitleSeeds: string[];
  smallPrescriptions: string[];
  safeReading: string;
  avoidExpressions?: string[];
};

function expansionLocalized(input: ExpansionLocalizedInput): LocalizedSymbolEntry {
  return localized({
    ...input,
    avoidExpressions: input.avoidExpressions ?? ["미래를 단정하기", "현실 사건을 예언처럼 말하기"],
  });
}

function researchedExpansionSymbol(
  input: Omit<ActiveSymbolInput, "ko" | "en"> & {
    ko: ExpansionLocalizedInput;
    en: ExpansionLocalizedInput;
  },
): SymbolEntry {
  return activeSymbol({
    ...input,
    ko: expansionLocalized(input.ko),
    en: expansionLocalized(input.en),
  });
}

type ExpansionSceneSeed = {
  key: string;
  reading: string;
  triggerTerms: string[];
  weight?: number;
  fortuneValence?: SceneModifier["fortuneValence"];
};

type CompactExpansionLocalizedInput = Omit<
  ExpansionLocalizedInput,
  "sceneModifiers" | "contextQuestions" | "metaphorHooks" | "cardTitleSeeds" | "smallPrescriptions"
> & {
  scenes: ExpansionSceneSeed[];
  contextQuestions: [string, string];
  metaphorHooks: [string, string];
  cardTitleSeeds: [string, string];
  smallPrescription: string;
};

function compactExpansionLocalized(input: CompactExpansionLocalizedInput): ExpansionLocalizedInput {
  const { scenes, smallPrescription, ...localizedInput } = input;

  return {
    ...localizedInput,
    sceneModifiers: Object.fromEntries(
      scenes.map((scene) => [
        scene.key,
        modifier(scene.reading, scene.triggerTerms, scene.weight ?? 0.82, scene.fortuneValence),
      ]),
    ),
    smallPrescriptions: [smallPrescription],
  };
}

function compactExpansionSymbol(
  input: Omit<ActiveSymbolInput, "ko" | "en"> & {
    ko: CompactExpansionLocalizedInput;
    en: CompactExpansionLocalizedInput;
  },
): SymbolEntry {
  return researchedExpansionSymbol({
    ...input,
    ko: compactExpansionLocalized(input.ko),
    en: compactExpansionLocalized(input.en),
  });
}

